// Overpass returns { elements: [ { center: {lat, lon}, tags: { 'addr:housenumber', 'addr:street', ... } } ] }
// Already includes coordinates — no geocoding step needed.
const elements = $json.elements || [];
return elements
  .filter(el => el.center && el.tags?.['addr:housenumber'] && el.tags?.['addr:street'])
  .map(el => {
    const t = el.tags;
    const city = t['addr:city'] || t['addr:suburb'] || '';
    const state = t['addr:state'] || '';
    const postcode = t['addr:postcode'] || '';
    const address = `${t['addr:housenumber']} ${t['addr:street']}, ${city}, ${state} ${postcode}`.trim();
    return { json: { address, suburb: city, city, state, postcode, lat: el.center.lat, lng: el.center.lon, propertyType: 'house', source: 'openstreetmap' } };
  })
  .filter(i => i.json.address && i.json.lat && i.json.lng);

// Score: dead=3, patchy=1.5, healthy=0, no-visible-lawn=-10; tier A=3,B=2,C=1
// Only pass standaloneHouse=true properties — filters out apartments, units etc.
const scored = items
  .map(i => {
    const c = JSON.parse(i.json.choices[0].message.content);
    if (!c.standaloneHouse) return null;
    const condScore = { dead: 3, patchy: 1.5, healthy: 0, 'no-visible-lawn': -10 }[c.lawnCondition] ?? 0;
    const tierScore = { A: 3, B: 2, C: 1 }[c.houseQualityTier] ?? 0;
    return { json: { ...i.json, ...c, score: condScore * (c.lawnConfidence ?? 1) + tierScore } };
  })
  .filter(Boolean);
scored.sort((a, b) => b.json.score - a.json.score);
if (!scored.length) throw new Error('No scoreable leads this run.');
return [scored[0]];

// Gemini returns the rendered image as base64 inside candidates[0].content.parts[].inline_data.data
const part = $json.candidates?.[0]?.content?.parts?.find(p => p.inline_data);
if (!part) throw new Error('Gemini render returned no image data.');
return [{
  json: { ...$('5. Rank & Select Top Lead').item.json },
  binary: {
    data: {
      data: part.inline_data.data,
      mimeType: part.inline_data.mime_type || 'image/png',
      fileName: 'rendered-lawn.png'
    }
  }
}];

// Stub: wire to a US property/owner lookup API (e.g. ATTOM, BatchData, or county assessor records).
// For demo purposes, defaults to 'Homeowner' so the pipeline completes end-to-end.
return items.map(i => ({ json: { ...i.json, ownerName: i.json.ownerName || 'Homeowner' } }));
